<script setup>
import { computed } from 'vue'
import { useVacanciesStore } from '../stores/vacancies'
const store=useVacanciesStore(); const {filters}=store; const options=(categoria)=>computed(()=>store.catalogs.filter(c=>c.categoria===categoria))
function clear(){store.setFilters({keyword:'',area:'',departamento:'',ubicacion:'',modalidad:'',contrato:'',jornada:''})}
</script>
<template><div class="card border border-stone-100 p-5"><div class="grid gap-3 md:grid-cols-2 xl:grid-cols-4"><input v-model="filters.keyword" class="input-field" placeholder="Puesto o palabra clave"/><select v-model="filters.area" class="input-field"><option value="">Todas las áreas</option><option v-for="x in options('area_profesional').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><select v-model="filters.departamento" class="input-field"><option value="">Todos los departamentos</option><option v-for="x in options('departamento').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><select v-model="filters.ubicacion" class="input-field"><option value="">Todas las ubicaciones</option><option v-for="x in options('ubicacion').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><select v-model="filters.modalidad" class="input-field"><option value="">Todas las modalidades</option><option v-for="x in options('modalidad').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><select v-model="filters.contrato" class="input-field"><option value="">Todos los contratos</option><option v-for="x in options('tipo_contrato').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><select v-model="filters.jornada" class="input-field"><option value="">Todas las jornadas</option><option v-for="x in options('jornada').value" :key="x.id" :value="x.id">{{x.nombre}}</option></select><button @click="clear" class="text-sm font-semibold text-brand-600 hover:text-brand-700">Limpiar filtros</button></div></div></template>
